using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Provides a web search tool that queries a search API and returns results.
/// Uses the Brave Search API when BRAVE_API_KEY is set; otherwise returns
/// simulated results so the agent loop can be demonstrated without a key.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _http;
    private readonly string? _braveApiKey;

    public WebSearchTool(HttpClient http)
    {
        _http = http;
        _braveApiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");
    }

    [Description("Search the web for information on a given query. Returns titles, URLs, and text snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        if (!string.IsNullOrWhiteSpace(_braveApiKey))
        {
            return await SearchBraveAsync(query, cancellationToken);
        }

        return SimulateSearch(query);
    }

    // ── Brave Search API integration ──────────────────────────────────
    private async Task<string> SearchBraveAsync(string query, CancellationToken ct)
    {
        var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5");
        request.Headers.Add("Accept", "application/json");
        request.Headers.Add("X-Subscription-Token", _braveApiKey);

        var response = await _http.SendAsync(request, ct);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(ct), cancellationToken: ct);

        var results = doc.RootElement
            .GetProperty("web")
            .GetProperty("results");

        var lines = new List<string>();
        foreach (var r in results.EnumerateArray())
        {
            var title = r.GetProperty("title").GetString();
            var url = r.GetProperty("url").GetString();
            var snippet = r.TryGetProperty("description", out var d) ? d.GetString() : "";
            lines.Add($"- **{title}**\n  {url}\n  {snippet}");
        }

        return string.Join("\n\n", lines);
    }

    // ── Simulated results for demo / offline usage ────────────────────
    private static string SimulateSearch(string query)
    {
        return $"""
            Search results for "{query}":

            1. "Overview of {query} — Wikipedia"
               https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}
               A comprehensive overview covering the history, key concepts, and current
               state of {query}. The topic has seen significant developments in recent years
               with growing interest from both academia and industry.

            2. "Recent Advances in {query} — Nature Reviews"
               https://nature.com/articles/{Uri.EscapeDataString(query)}-review-2026
               This 2026 review highlights breakthroughs including improved methodologies,
               new theoretical frameworks, and practical applications that are reshaping the field.

            3. "{query}: A Practical Guide — O'Reilly Media"
               https://oreilly.com/library/{Uri.EscapeDataString(query)}-guide
               Hands-on guide covering foundational principles, best practices, and real-world
               case studies. Frequently cited as the go-to resource for practitioners.

            4. "The Future of {query} — MIT Technology Review"
               https://technologyreview.com/2026/{Uri.EscapeDataString(query)}-future
               Experts predict that {query} will transform multiple industries over the next
               decade, with particular impact on healthcare, education, and sustainability.

            5. "Challenges and Limitations of {query} — ACM Computing Surveys"
               https://dl.acm.org/doi/10.1145/{Uri.EscapeDataString(query)}
               A balanced analysis of current limitations including scalability concerns,
               ethical considerations, and areas where more research is needed.
            """;
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking tools that let the agent record and review research
/// findings across multiple search iterations before writing a final summary.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<(DateTime Timestamp, string Content)> _notes = [];

    [Description("Save a research note. Use this to record key findings, facts, or quotes discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add((DateTime.UtcNow, content));
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n", _notes.Select((n, i) =>
            $"[{i + 1}] ({n.Timestamp:HH:mm:ss}) {n.Content}"));
    }

    [Description("Clear all saved notes to start fresh.")]
    public string ClearNotes()
    {
        var count = _notes.Count;
        _notes.Clear();
        return $"Cleared {count} note(s).";
    }
}

