using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent;

// ── Configuration ─────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18"; // pinned version for reproducibility
const int maxIterations = 15;

// ── Services ──────────────────────────────────────────────────────────
var services = new ServiceCollection();

services.AddLogging(b => b
    .AddConsole()
    .SetMinimumLevel(LogLevel.Warning));

services.AddHttpClient();

var sp = services.BuildServiceProvider();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// ── Chat client via MEAI abstraction ──────────────────────────────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Tools ─────────────────────────────────────────────────────────────
var httpFactory = sp.GetRequiredService<IHttpClientFactory>();
var webSearch = new WebSearchTool(httpFactory.CreateClient());
var noteTaking = new NoteTakingTool();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(noteTaking.AddNote),
    AIFunctionFactory.Create(noteTaking.GetNotes),
    AIFunctionFactory.Create(noteTaking.ClearNotes),
};

// ── Agent ─────────────────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: """
        You are a thorough research assistant. When given a topic:

        1. Search the web 2-3 times with varied queries to gather broad information.
        2. After each search, use AddNote to record the most important findings.
        3. After gathering enough information, use GetNotes to review everything.
        4. Write a well-structured summary with sections:
           - **Overview**: What the topic is and why it matters.
           - **Key Findings**: The most important facts and developments.
           - **Different Perspectives**: Varying viewpoints or approaches.
           - **Conclusion**: A brief synthesis of the research.

        Always cite your sources with URLs when available.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and synthesizing findings.",
    tools: tools,
    loggerFactory: loggerFactory,
    serviceProvider: sp);

// ── Run ───────────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (v1.0)       ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic (or press Enter for default): ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
    topic = "the current state of quantum computing";

Console.WriteLine();
Console.WriteLine($"🔍 Researching: {topic}");
Console.WriteLine(new string('─', 60));
Console.WriteLine();

using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(3));

var session = await agent.CreateSessionAsync(cts.Token);

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
};

var runOptions = new ChatClientAgentRunOptions(chatOptions)
{
    MaximumIterations = maxIterations,
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions,
    cts.Token))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("✅ Research complete.");

